<?php require_once "../config/database.php"; require_once "../includes/session.php"; requireAdmin(); 
if(isset($_POST['add_room'])){$conn->prepare("INSERT INTO rooms(room_name,floor,room_type,capacity,price,status,image_url,description,amenities,rules) VALUES(?,?,?,?,?,?,?,?,?,?)")->execute([$_POST['room_name'],$_POST['floor'],$_POST['room_type'],$_POST['capacity'],$_POST['price'],$_POST['status'],$_POST['image_url'],$_POST['description'],$_POST['amenities'],$_POST['rules']]);}if(isset($_GET['delete']))$conn->prepare("DELETE FROM rooms WHERE room_id=?")->execute([$_GET['delete']]);include "../includes/header.php";$rows=$conn->query("SELECT * FROM rooms ORDER BY room_id DESC")->fetchAll(PDO::FETCH_ASSOC);?><div class="container"><h1 class="section-title">Rooms</h1><div class="form-card"><form method="POST"><input name="room_name" placeholder="Room Name"><input name="floor" placeholder="Floor"><select name="room_type"><option>Standard</option><option>Premium</option><option>Deluxe</option></select><input type="number" name="capacity" placeholder="Capacity"><input type="number" step="0.01" name="price" placeholder="Price"><select name="status"><option>Available</option><option>Occupied</option><option>Maintenance</option></select><input name="image_url" placeholder="Image URL"><textarea name="description" placeholder="Description"></textarea><textarea name="amenities" placeholder="Amenities"></textarea><textarea name="rules" placeholder="Rules"></textarea><button name="add_room" class="btn">Add Room</button></form></div><div class="table-wrap"><table><tr><th>Room</th><th>Type</th><th>Price</th><th>Status</th><th>Action</th></tr><?php foreach($rows as $r):?><tr><td><?=e($r['room_name'])?></td><td><?=e($r['room_type'])?></td><td>₱<?=number_format($r['price'],2)?></td><td><?=$r['status']?></td><td><a onclick="return confirmDelete()" class="btn danger" href="?delete=<?=$r['room_id']?>">Delete</a></td></tr><?php endforeach;?></table></div></div><?php include "../includes/footer.php";?>
